import re

# Patterns for common sensitive values
_PATTERNS = [
    (re.compile(r'[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}'), '[EMAIL]'),
    (re.compile(r'\b(?:sk|pk|api)[-_][A-Za-z0-9]{16,}', re.I), '[API_KEY]'),
    (re.compile(r'\b\d{4}[\s\-]?\d{4}[\s\-]?\d{4}[\s\-]?\d{4}\b'), '[CARD]'),
    (re.compile(r'\b\d{3}[-.]?\d{2}[-.]?\d{4}\b'), '[SSN]'),
    (re.compile(r'(?i)password[\s:=]+\S+'), 'password=[REDACTED]'),
    (re.compile(r'(?i)bearer\s+[A-Za-z0-9\-._~+/]+=*'), 'Bearer [TOKEN]'),
]

def scrub(text: str) -> str:
    for pattern, replacement in _PATTERNS:
        text = pattern.sub(replacement, text)
    return text

def scrub_log_record(record: dict) -> dict:
    """Return a shallow copy of the record with sensitive fields scrubbed."""
    sensitive_fields = {"last_user_message", "response_text", "result", "final_answer"}
    cleaned = dict(record)
    for field in sensitive_fields:
        if field in cleaned and isinstance(cleaned[field], str):
            cleaned[field] = scrub(cleaned[field])
    if "args" in cleaned and isinstance(cleaned["args"], dict):
        cleaned["args"] = {k: scrub(str(v)) for k, v in cleaned["args"].items()}
    return cleaned

