import json, pathlib, anthropic

def load_trajectory(run_id: str, log_dir: str = "logs/trajectories") -> list[dict]:
    path = f"{log_dir}/{run_id}.jsonl"
    return [json.loads(line) for line in pathlib.Path(path).read_text().splitlines() if line]

def replay_trajectory(run_id: str, new_model: str) -> str:
    """
    Replay a logged trajectory with a different model.
    Tool results are taken from the log — no live tool calls.
    """
    events = load_trajectory(run_id)
    client = anthropic.Anthropic()

    # Extract the original task from run_start
    run_start = next(e for e in events if e["event"] == "run_start")
    task = run_start["task"]

    # Extract tool results in order from original log
    tool_results_log = [
        e for e in events if e["event"] == "tool_call"
    ]
    tool_result_iter = iter(tool_results_log)

    messages = [{"role": "user", "content": task}]
    tools = [
        {
            "name": "calculator",
            "description": "Evaluate a mathematical expression.",
            "input_schema": {
                "type": "object",
                "properties": {"expression": {"type": "string"}},
                "required": ["expression"],
            },
        }
    ]

    final = ""
    for _ in range(8):
        resp = client.messages.create(
            model=new_model, max_tokens=256, tools=tools, messages=messages
        )
        if resp.stop_reason == "end_turn":
            final = " ".join(b.text for b in resp.content if hasattr(b, "text"))
            break

        if resp.stop_reason == "tool_use":
            tool_res = []
            for block in resp.content:
                if block.type == "tool_use":
                    # Use the result from the log instead of calling the live tool
                    logged = next(tool_result_iter, None)
                    result = logged["result"] if logged else "No logged result."
                    tool_res.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": tool_res},
            ]

    return final

# Compare original vs new model on the same trajectory
import glob
for f in sorted(glob.glob("logs/trajectories/*.jsonl")):
    run_id = pathlib.Path(f).stem
    try:
        replayed = replay_trajectory(run_id, new_model="claude-haiku-4-5-20251001")
        print(f"Replay [{run_id}]: {replayed[:80]}")
    except StopIteration:
        print(f"Replay [{run_id}]: too few logged tool results to replay")
